        if not observations:
            continue

        for observation in observations:
            observation_timestamp = ""
            if observation.get("effectiveDateTime"):
                observation_timestamp = observation.get("effectiveDateTime")
            elif observation.get("issued"):
                observation_timestamp = observation.get("issued")

            if not observation_timestamp:
                continue

            if selected_observation is None or observation_timestamp > selected_timestamp:
                selected_observation = observation
                selected_timestamp = observation_timestamp
                selected_patient_query = patient_value

        if selected_observation is not None:
            break

    most_recent_by_test[test_label] = selected_observation

    if selected_observation is None:
        status_by_test[test_label] = "No usable Observation results found for the requested lab code using any provided patient query value."
